  const pMap = (primary && primary.kind && Object.keys(primary.map).length) ? primary.map : null;
  if (pMap) { rec.kind = primary.kind; rec.glBat = primary.glBat || []; rec.glPit = primary.glPit || []; }
  // Hitting
